    send_whats_app_message(message, meta_api_version, origination_phone_number_id, params::Dict{String,<:Any})

Send a WhatsApp message. For examples of sending a message using the Amazon Web Services
CLI, see [Sending messages](https://docs.aws.amazon.com/social-messaging/latest/userguide/send-message.html)
in the *<i>Amazon Web Services End User Messaging Social User Guide* </i>.

# Arguments

- `message`: The message to send through WhatsApp. The length is in KB. The message field
  passes through a WhatsApp Message object, see [Messages](https://developers.facebook.com/docs/whatsapp/cloud-api/reference/messages)
  in the *WhatsApp Business Platform Cloud API Reference*.

- `meta_api_version`: The API version for the request formatted as `v{VersionNumber}`. For a
  list of supported API versions and Amazon Web Services Regions, see [*Amazon Web Services End User Messaging Social API* Service Endpoints](https://docs.aws.amazon.com/general/latest/gr/end-user-messaging.html)
  in the *Amazon Web Services General Reference*.

- `origination_phone_number_id`: The ID of the phone number used to send the WhatsApp
  message. If you are sending a media file only the `originationPhoneNumberId` used to
  upload the file can be used. Phone number identifiers are formatted as
  `phone-number-id-01234567890123456789012345678901`. Use [GetLinkedWhatsAppBusinessAccount](https://docs.aws.amazon.com/social-messaging/latest/APIReference/API_GetLinkedWhatsAppBusinessAccount.html)
  to find a phone number's id.
"""
function send_whats_app_message end

function send_whats_app_message(
    message,
    metaApiVersion,
    originationPhoneNumberId;
    aws_config::AbstractAWSConfig=current_aws_config(),
)
    return socialmessaging(
        "POST",
        "/v1/whatsapp/send",
        Dict{String,Any}(
            "message" => message,
            "metaApiVersion" => metaApiVersion,
            "originationPhoneNumberId" => originationPhoneNumberId,
        );
        aws_config,
        feature_set=SERVICE_FEATURE_SET,
    )
end

function send_whats_app_message(
    message,
    metaApiVersion,
    originationPhoneNumberId,
    params::AbstractDict{String};
    aws_config::AbstractAWSConfig=current_aws_config(),
)
    return socialmessaging(
        "POST",
        "/v1/whatsapp/send",
        Dict{String,Any}(
            mergewith(
                _merge,
                Dict{String,Any}(
                    "message" => message,
                    "metaApiVersion" => metaApiVersion,
                    "originationPhoneNumberId" => originationPhoneNumberId,
                ),
                params,
            ),
        );
        aws_config,
        feature_set=SERVICE_FEATURE_SET,
    )
end

"""
    tag_resource(resource_arn, tags)
    tag_resource(resource_arn, tags, params::Dict{String,<:Any})

Adds or overwrites only the specified tags for the specified resource. When you specify an
existing tag key, the value is overwritten with the new value.

# Arguments

- `resource_arn`: The Amazon Resource Name (ARN) of the resource to tag.
- `tags`: The tags to add to the resource.
"""
function tag_resource end

function tag_resource(resourceArn, tags; aws_config::AbstractAWSConfig=current_aws_config())
    return socialmessaging(
        "POST",
        "/v1/tags/tag-resource",
        Dict{String,Any}("resourceArn" => resourceArn, "tags" => tags);
        aws_config,
        feature_set=SERVICE_FEATURE_SET,
    )
end

