"""
    update_whats_app_message_template(id, meta_template_id)
    update_whats_app_message_template(id, meta_template_id, params::Dict{String,<:Any})

Updates an existing WhatsApp message template.

# Arguments

- `id`: The ID of the WhatsApp Business Account associated with this template.
- `meta_template_id`: The numeric ID of the template assigned by Meta.

# Optional Parameters

Optional parameters can be passed as a `params::Dict{String,<:Any}`. Valid keys are:

- `"ctaUrlLinkTrackingOptedOut"`: When true, disables click tracking for call-to-action URL
  buttons in the template.
- `"parameterFormat"`: The format specification for parameters in the template, this can be
  either 'named' or 'positional'.
- `"templateCategory"`: The new category for the template (for example, UTILITY or
  MARKETING).
- `"templateComponents"`: The updated components of the template as a JSON blob (maximum
  3000 characters).
"""
function update_whats_app_message_template end

function update_whats_app_message_template(
    id, metaTemplateId; aws_config::AbstractAWSConfig=current_aws_config()
)
    return socialmessaging(
        "POST",
        "/v1/whatsapp/template",
        Dict{String,Any}("id" => id, "metaTemplateId" => metaTemplateId);
        aws_config,
        feature_set=SERVICE_FEATURE_SET,
    )
end

function update_whats_app_message_template(
    id,
    metaTemplateId,
    params::AbstractDict{String};
    aws_config::AbstractAWSConfig=current_aws_config(),
)
    return socialmessaging(
        "POST",
        "/v1/whatsapp/template",
        Dict{String,Any}(
            mergewith(
                _merge,
                Dict{String,Any}("id" => id, "metaTemplateId" => metaTemplateId),
                params,
            ),
        );
        aws_config,
        feature_set=SERVICE_FEATURE_SET,
    )
end
